import copy

order = {
    'customer': 'acme-corp',
    'items': [
        {'sku': 'WIDGET-01', 'qty': 5},
        {'sku': 'BOLT-07', 'qty': 100}
    ]
}

order_copy = copy.deepcopy(order)
order_copy['items'].append({'sku': 'NUT-03', 'qty': 50})

print('original items:', len(order['items']))   # 2
print('copy items:', len(order_copy['items']))  # 3
